 3→import cn.hutool.json.JSONUtil;
 4→import com.fasterxml.jackson.databind.ObjectMapper;
 5→import com.rabbitmq.client.Channel;
 6→import com.yottastudios.ns.collabspace.announcement.entity.AnnouncementEntity;
 7→import com.yottastudios.ns.collabspace.announcement.enums.AnnouncementStatus;
 8→import com.yottastudios.ns.collabspace.announcement.enums.AnnouncementType;
 9→import com.yottastudios.ns.collabspace.announcement.mapper.AnnouncementMapper;
10→import com.yottastudios.ns.collabspace.starter.socketio.core.MessageTypeEnum;
11→import com.yottastudios.ns.collabspace.starter.socketio.core.WebSocketHandler;
12→import com.yottastudios.ns.collabspace.starter.socketio.core.WebSocketResponseModel;
13→import jakarta.annotation.Resource;
14→import lombok.extern.slf4j.Slf4j;
15→import org.springframework.amqp.core.Message;
16→import org.springframework.amqp.rabbit.annotation.RabbitListener;
17→import org.springframework.stereotype.Component;
18→import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;
19→
20→import java.io.IOException;
21→import java.time.LocalDateTime;
22→
23→import static com.yottastudios.ns.collabspace.shared.config.QueueConfig.ANNOUNCEMENT_QUEUE;
24→
25→@Slf4j
26→@Component
27→@ConditionalOnProperty(name = "mq.enabled", havingValue = "true", matchIfMissing = true)
28→public class AnnouncementConsumer {
29→    @Resource
30→    AnnouncementMapper announcementMapper;
31→
32→    @Resource
33→    WebSocketHandler webSocketHandler;
34→
35→    @RabbitListener(queues = ANNOUNCEMENT_QUEUE)
36→    public void handle(Message message, Channel channel) throws IOException {
37→        log.info("Received announcement message: {}", message);
38→        String body = new String(message.getBody());
39→        Long announcementId = Long.parseLong(body);
40→        try {
41→        AnnouncementEntity announce = announcementMapper.selectById(announcementId);
42→        if (announce == null || announce.getStatus() == AnnouncementStatus.CANCELLED.getCode()
43→        || announce.getType() == AnnouncementType.DRAFT.getCode()) {
44→            throw new RuntimeException("公告不需要发布");
45→        }
46→        announce.setStatus(AnnouncementStatus.PUBLISHED.getCode());
47→        announce.setUpdatedAt(LocalDateTime.now());
48→        announcementMapper.updateById(announce);
49→
50→         WebSocketResponseModel webSocketResponseModel = WebSocketResponseModel.builder().type(MessageTypeEnum.ADD_ANNOUNCEMENT.getType())
51→                    .message("更新公告").status(200).data(null).build();
52→         String msg = JSONUtil.toJsonStr(webSocketResponseModel);
53→         webSocketHandler.sendAllUserToWebSocketClient(msg);
54→        } catch (Exception e) {
55→            log.error("Failed to publish timed announcement, id={}", announcementId);
56→        } finally {
57→            // 先不考虑重试
58→            long deliveryTag = message.getMessageProperties().getDeliveryTag();
59→            channel.basicAck(deliveryTag, false);
60→        }
61→    }
62→}
